","new_string":"        if (node.elementType == THEN || node.elementType == ELSE) {
            if (node.firstChildNode?.elementType == BLOCK) {
                return
            }

            if (node.elementType == ELSE) {
                // Do not enforce curly braces around an `else if` branch, even when the full if-else chain spans multiple lines.
                // Example:
                //   if (...) {
                //   } else if (...) {
                //   }
                var child = node.firstChildNode
                while (child != null && (child.isWhiteSpace() || child.isPartOfComment())) {
                    child = child.treeNext
                }
                if (child?.elementType == ELSE_KEYWORD) {
                    child = child.treeNext
                    while (child != null && (child.isWhiteSpace() || child.isPartOfComment())) {
                        child = child.treeNext
                    }
                }
                if (child?.elementType == IF) {
                    return
                }
            }

            if (!node.treePrev.textContains('\n')) {
                if (node.firstChildNode.elementType == IF) {
                    // Allow single line for:
                    // else if (...)
                    return
                }
                if (!node.treeParent.textContains('\n')) {
                    // Allow single line if statements as long as they are really simple (e.g. do not contain newlines)
                    //    if (...) <statement> // no else statement
                    //    if (...) <statement> else <statement>
                    return
                }
            }
