 50→    override fun beforeVisitChildNodes(
 51→        node: ASTNode,
 52→        autoCorrect: Boolean,
 53→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 54→    ) {
 55→        if (node.elementType == THEN || node.elementType == ELSE) {
 56→            if (node.firstChildNode?.elementType == BLOCK) {
 57→                return
 58→            }
 59→
 60→            if (node.elementType == ELSE) {
 61→                // Do not enforce curly braces around an `else if` branch, even when the full if-else chain spans multiple lines.
 62→                // Example:
 63→                //   if (...) {
 64→                //   } else if (...) {
 65→                //   }
 66→                var child = node.firstChildNode
 67→                while (child != null && (child.isWhiteSpace() || child.isPartOfComment())) {
 68→                    child = child.treeNext
 69→                }
 70→                if (child?.elementType == ELSE_KEYWORD) {
 71→                    child = child.treeNext
 72→                    while (child != null && (child.isWhiteSpace() || child.isPartOfComment())) {
 73→                        child = child.treeNext
 74→                    }
 75→                }
 76→                if (child?.elementType == IF) {
 77→                    return
 78→                }
 79→            }
 80→
