103→        val prevLeaves =
104→            node
105→                .leaves(forward = false)
106→                .takeWhile { it.elementType !in listOf(RPAR, ELSE_KEYWORD) }
107→                .toList()
108→                .reversed()
109→        val nextLeaves =
