111→                .leaves(forward = true)
112→                .takeWhile { it.isWhiteSpaceWithoutNewline() || it.isPartOfComment() }
113→                .toList()
114→                .dropLastWhile { it.isWhiteSpaceWithoutNewline() }
115→
