128→                .dropWhile { it.isWhiteSpace() }
129→                .forEach(::addChild)
130→            addChild(previousChild)
131→            nextLeaves.forEach(::addChild)
132→            addChild(PsiWhiteSpaceImpl(node.indent()))
133→            addChild(LeafPsiElement(RBRACE, "}"))
134→        }
