import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class MultiLineIfElseRuleElseIfRegressionTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given a multiline if expression with else-if and elvis operator then keep else-if as is`() {
        val code =
            """
            fun foo(showFilter: Boolean, activeTabIndex: Int) {
                val x = if (showFilter) {
                    1
                } else if (activeTabIndex == 0) {
                    2
                } else {
                    null
                } ?: 0
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multiline if expression with else-if and chained call then keep else-if as is`() {
        val code =
            """
            fun foo(bar1: Boolean, bar2: Boolean) {
                val foo = if (bar1) {
                    "bar1"
                } else if (bar2) {
                    "bar2"
                } else {
                    "bar3"
                }.plus("foo")
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

